import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Divider, FormLabel, Grid, Paper } from '@material-ui/core';
import classNames from 'classnames';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faUserAlt } from '@fortawesome/free-solid-svg-icons';


const style = theme => ({
    root: {
        padding : 10,
    },
    profile : {
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
        flexDirection : "column",
    },
    accRow : {
        display : 'flex',
        fontSize : 12,
        padding : 10,
    },
    accLabel : {
        width : "50%",
    },
    actionLabel : {
        textDecoration : "underline",
        cursor : "pointer",
    },
    item : {
        display : "flex",
        flexDirection : "column",
        fontSize : 12,
    },
    cashIn : {
        display : "flex",
        flexDirection : "column",
        fontSize : 12,
        background : theme.colors.secondary,
        color : theme.colors.white,
        padding : 10,
        borderRadius : 10,
    }
})
class _HIRAccountUserActionCard extends Component {
    render() {
        const {classes, totals, user, payments, deposit} = this.props,
        {myProfile, _id} = user,
        {lastName, firstName, email, phone} = myProfile || {},
        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
        const cashIn = (payments?.["cashPayment"] || 0) + (deposit || 0);
        return (
            <Paper className={classes.root}>
                <Grid container>
                    <Grid item xs={12} sm={4} md={4} lg={4} xl={4}>
                        <div className={classes.profile}>
                            <FontAwesomeIcon size="4x" icon={faUserAlt}/>
                            <div style={{marginTop : 10, fontSize : 10, textAlign : 'center', justifyContent : "center", display : 'flex', flexDirection : "column"}}>
                                <span style={{fontSize : 12, fontWeight : "bold"}}>{name}</span>
                                <span>{email}</span>
                                <span>{phone}</span>
                            </div>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={8} md={8} lg={8} xl={8}>
                        <div className={classes.account}>
                            <div style={{textAlign : "center"}}><FormLabel> Accounts </FormLabel></div>
                            <div style={{marginTop : 20}}>
                                <Grid container>
                                    <Grid item xs={4} sm={4} md={4} lg={4} xl={4}>
                                        <div className={classes.item}>
                                            <strong>Cash</strong>
                                            <span>N {Number(payments?.["cashPayment"] || 0).toLocaleString()}</span>
                                        </div>
                                    </Grid>
                                    <Grid item xs={4} sm={4} md={4} lg={4} xl={4}>
                                        <div className={classes.item}>
                                            <strong>Deposit</strong>
                                            <span>N {Number(deposit || 0).toLocaleString()}</span>
                                        </div>
                                    </Grid>
                                    <Grid item xs={4} sm={4} md={4} lg={4} xl={4}>
                                        <div className={classes.cashIn}>
                                            <strong>Total Cash</strong>
                                            <span>N {Number(cashIn || 0).toLocaleString()}</span>
                                        </div>
                                    </Grid>
                                    <Grid item xs={4} sm={4} md={4} lg={4} xl={4}>
                                        <div className={classes.item}>
                                            <strong>Credit</strong>
                                            <span>N {Number(payments?.["useCredit"] || 0).toLocaleString()}</span>
                                        </div>
                                    </Grid>
                                    <Grid item xs={4} sm={4} md={4} lg={4} xl={4}>
                                        <div className={classes.item}>
                                            <strong>Debit</strong>
                                            <span>N {Number(payments?.["addToDebt"] || 0).toLocaleString()}</span>
                                        </div>
                                    </Grid>
                                </Grid>
                            </div>
                        </div>
                    </Grid>
                </Grid>
            </Paper>
        );
    }
}


_HIRAccountUserActionCard.propTypes = {
    classes : PropTypes.object.isRequired, 
    user : PropTypes.array,
    totals : PropTypes.array,
};
const mapStateToProps = state => ({
    state
})


export const HIRAccountUserActionCard = connect(mapStateToProps)(withStyles(style)(_HIRAccountUserActionCard));
export {HIRAccountUserActionCard as default}