import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, Checkbox, FormControlLabel, Typography, CircularProgress, TableCell, Hidden, FormLabel } from '@material-ui/core';
import { CalendarToday, CalendarViewDay } from '@material-ui/icons';
import Calendar from 'react-calendar';
import { HIRButton, HIRStartEndDates } from '../Includes';
import { hirAccountActions, hirAccountStrings } from '../HIRAccounts';
import { errorNotice, monthSelections, warningNotice, MyTable, MyDialog, hirUtil } from '../utils';
import { history } from '../../../helpers';
import { hirRouteNames } from '../routeNames';
import ReactToPrint from 'react-to-print';
import { Fragment } from 'react';
import { hirSettingStrings } from '../HIRSettings';
import { HIRAccountUserActionCard } from './HIRAccountUserActionCard';

const style = theme => ({
    root: {
    },
    header : {
        color : theme.colors.primary,
        fontWeight : "bold",
    },
    progress : {
        width : "30px !important",
        height : "30px !important",
    },
    cell : {
        fontSize : 11, 
        padding : 5,
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
    cardRoot : {
        background : "#e6e5e5",
        marginBottom : 10,
    },
    totalCashContainer : {
        display : "flex",
        justifyContent : 'flex-end',
    },
    totalCash: {
        display : "flex",
        fontSize : 12,
        background : theme.colors.secondary,
        color : theme.colors.white,
        padding : 20,
        borderRadius : 10,
        fontSize : 14,
        fontWeight : "bold",
        "&::before" : {
            content : "\"Total = N\"",
        }
    }
})
class _HIRAccountUserActions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            monthOnlyView : false,
            calenderDialog : false,
            dateSearchBtnLoading : false,
            searchDate : new Date(),
            dialogType : "date"
        }
    }
    componentDidMount() {
        this.searchByDate();
    }
    
    onChange(e){
        const value = e.target.checked;
        this.setState({monthOnlyView : value},()=>{
            this.searchByDate();
        });
    }
    searchByDate(fromCalenderDialog){
        const {searchDate, monthOnlyView, dialogType, startDate, endDate} = this.state;
        const {dispatch}=this.props;
        if(fromCalenderDialog){
            this.setState({dateSearchBtnLoading : true});
        }
        if(dialogType === "date"){
            if(!searchDate) return errorNotice("No date Selected", dispatch);            
            const date = new Date(searchDate);
            hirAccountActions.getUserDepositsByDate(
                date.getFullYear(), 
                date.getMonth() + 1,
                fromCalenderDialog ? date.getDate() :
                (monthOnlyView ? null : date.getDate()),
                (done, result, message)=>{
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
            hirAccountActions.getUserPaymentsByDate(
                date.getFullYear(), 
                date.getMonth() + 1,
                fromCalenderDialog ? date.getDate() :
                (monthOnlyView ? null : date.getDate()),
                (done, result, message)=>{
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }else {
            if(!startDate) return errorNotice("Start date isn't selected", dispatch);
            if(!endDate) return errorNotice("End date isn't selected", dispatch);
            const date1 = new Date(endDate), date2 = new Date(startDate);
            if((date1.getFullYear() * 12 + date1.getMonth()) - (date2.getFullYear()*12 + date2.getMonth()) > 3){
                return warningNotice("Please make your month range within 3 months", dispatch);
            }
            if(fromCalenderDialog){
                this.setState({dateSearchBtnLoading : true});
            } 
            hirAccountActions.searchUserPaymentsByDateRange(
                startDate, endDate, {}, done => {
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }
    }
    cellMapFormat = ({row, cellMap})=>{
        const {
            classes,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(row.lastLine){
            switch(cellMap){
                case "_id" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>;
                case "total" : return <TableCell className={classes.cell}>
                    <strong>{Number(row.total).toLocaleString()}</strong>
                </TableCell> 
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }else{
            const user = row._id[0];
            let userId, profile;
            if(user){
                userId = user._id;
                profile = user.myProfile;
            }
            switch(cellMap){
                case "email" : 
                    return <TableCell className={classes.cell}>
                        {profile && profile.email}
                </TableCell>
                case "phone" : 
                    return <TableCell className={classes.cell}>
                        {profile && profile.phone}
                </TableCell>
                case "_id" : 
                    return <TableCell className={classes.cell}>
                        {userId && String(userId).padStart(6, "0")}
                </TableCell>
                case "name" : 
                    return <TableCell className={classes.cell}>
                        {profile && (profile.lastName+", "+profile.firstName)}
                </TableCell>
                case "total" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    rowAction = row=>()=>{
        if(row.lastLine) return;
        const user = row._id[0];
        const {monthOnlyView, searchDate} = this.state
        history.push(
            hirRouteNames.accountViewPaymentDetail, 
            {
                userId : user._id, type : "user",
                monthOnlyView, date : searchDate,
                user,
            }
        )
    }
    viewUserPayments = user => () => {
        const {monthOnlyView, searchDate} = this.state
        history.push(
            hirRouteNames.accountViewPaymentDetail, 
            {
                userId : user._id, type : "user",
                monthOnlyView, date : searchDate,
                user,
            }
        )
    }
    render() {
        let {
            classes,
            [hirAccountStrings.userBasedPayments] : userBasedPayments,
            [hirAccountStrings.userBasedDeposits] : userBasedDeposits,
        } = this.props;
        let {monthOnlyView, calenderDialog, 
            dateSearchBtnLoading, searchDate : date, dialogType,
            endDate, startDate
        } = this.state;
        let searchDate = new Date(date);
        let ptotal = 0, dtotal = 0;
        const users = [], userPayments = {}, userDeposits = [];
        if(userBasedPayments){
            for (let i = 0; i < userBasedPayments.length; i++) {
                const {total : paymentTotal, _id : {accountAction="cashPayment", user}} = userBasedPayments[i];
                if(!isNaN(parseInt(paymentTotal))) {
                    ptotal += paymentTotal;
                }
                if(!users.find(i=>i._id === user._id))
                    users.push(user);
                if(!userPayments[user._id])
                    userPayments[user._id] = {[accountAction] : paymentTotal};
                else userPayments[user._id][accountAction] = paymentTotal;
            }
        }
        if(userBasedDeposits){
            for (let i = 0; i < userBasedDeposits.length; i++) {
                const {total : depositTotal, _id : groupById} = userBasedDeposits[i];
                if(!isNaN(parseInt(depositTotal))) {
                    dtotal += depositTotal;
                }
                const user = groupById && groupById[0];
                if(!users.find(i=>i._id === user._id))
                    users.push(user);
                userDeposits.push({_id : user._id, total : depositTotal});
            }
        }
        let totalCash = 0;
        return (
            <div className={classes.root}>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({calenderDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnlyView}
                            onChange={this.onChange.bind(this)}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({calenderDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                </div>
                <FormLabel>
                    {dialogType === "date" ?
                        (monthOnlyView ? 
                            searchDate.getFullYear()+", "+(monthSelections.find(item=>item.value ==searchDate.getMonth()+1).name) : 
                            searchDate.toDateString()
                        ): new Date(startDate).toLocaleDateString() + " to " + 
                        new Date(endDate).toLocaleDateString()}</FormLabel>
                <div style={{width : "100%"}} ref={e=>this.printComponent=e}>
                    {users && users.map((user, index) => {
                        const depositTotal = userDeposits.find(i=>i._id===user._id);
                        totalCash += (userPayments?.[user._id]?.["cashPayment"] || 0) + 
                            (depositTotal?.total || 0);
                        return <HIRAccountUserActionCard
                            classes={{
                                root : classes.cardRoot
                            }}
                            user={user}
                            key={index}
                            payments={userPayments[user._id]}
                            deposit={depositTotal?.total}
                        />
                    })}
                    <Hidden xsUp>
                        <MyTable
                            titleProps={{
                                style : {
                                    fontSize : 14
                                }
                            }}
                            header={["ID", "Name", "Email", "Phone", "Total Amount"]}
                            dataMap={["_id", "name", "email", "phone", "total"]}
                            rowAction={this.rowAction.bind(this)}
                            data={userBasedPayments}
                            CellMap={this.cellMapFormat.bind(this)}
                            />
                    </Hidden>
                </div>
                <div className={classes.totalCashContainer}>
                    <span className={classes.totalCash}>{Number(totalCash).toLocaleString()}</span>
                </div>
                <ReactToPrint 
                    trigger={()=><button>Print</button>}
                    content={()=>this.printComponent}
                />
                <MyDialog open={calenderDialog}
                 close={()=>this.setState({calenderDialog : false})}>
                     <div style={{
                         display : "flex",
                         flexDirection : "column",
                         alignItems : "center",
                         justifyContent : "center"
                         }}>
                             {dialogType === "date" && <Fragment>
                                 <Typography paragraph className={classes.header}>Search Payment by dates</Typography>
                                <Calendar
                                    onChange={date=>this.setState({searchDate : date})}/>
                             </Fragment>}
                            {dialogType === "dateRange" && <Fragment>
                                <Typography paragraph className={classes.header}>Search Payment by dates range</Typography>
                                <HIRStartEndDates
                                    noTitle
                                    containerProps={{
                                        style : {
                                            width : "100%"
                                        }
                                    }}
                                    onDateChange={(startDate, endDate)=>this.setState({startDate, endDate})}/>
                            </Fragment>}
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                disabled={dateSearchBtnLoading}
                                onClick={()=>this.searchByDate(true)}>
                                    {dateSearchBtnLoading && 
                                    <CircularProgress color="secondary" 
                                        className={classes.progress}/>} Get Payments
                                </HIRButton>
                        </div>
                    </div>
                    
                 </MyDialog>            
            </div>
        );
    }
}


_HIRAccountUserActions.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirAccountReducer}) => ({
    [hirAccountStrings.userBasedPayments] : hirAccountReducer[hirAccountStrings.userBasedPayments],
    [hirAccountStrings.userBasedDeposits] : hirAccountReducer[hirAccountStrings.userBasedDeposits],
})


export const HIRAccountUserActions = connect(mapStateToProps)(withStyles(style)(_HIRAccountUserActions));
export {HIRAccountUserActions as default}